#!/usr/bin/env python3# -*- coding: utf-8 -*-"""AG_抓取COMEX白银库存.py因子: AG_INV_COMEX_SILVER = COMEX白银库存（吨）公式: 数据采集（无独立计算公式）当前状态: [OK] 正常- AKShare futures_comex_inventory(symbol='白银') 返回COMEX白银库存（吨）- 注意：默认参数symbol=None返回黄金数据，需显式传入symbol='白银'订阅优先级: 无需付费替代付费源: 无"""import sys, ossys.path.insert(0, os.path.join(os.path.dirname(os.path.abspath(__file__)), '..'))from common.db_utils import ensure_table, save_to_db, get_pit_dates, get_latest_valueimport akshare as akFACTOR_CODE = "AG_INV_COMEX_SILVER"SYMBOL = "AG"def fetch():    print("[L1] AKShare futures_comex_inventory(symbol='白银')...")    try:        df = ak.futures_comex_inventory(symbol='白银')        if df is not None and len(df) > 0:            row = df.iloc[-1]            val = float(row['COMEX白银库存量-吨'])            obs_date_str = str(row['日期'])[:10]            print(f"[L1] COMEX白银库存={val:.3f}吨 (obs={obs_date_str})")            return val, obs_date_str    except Exception as e:        print(f"[L1] 失败: {e}")    return None, Nonedef main():    ensure_table()    pub_date, obs_date = get_pit_dates()    print(f"=== {FACTOR_CODE} === obs={obs_date}")    val, data_date = fetch()    if val is not None:        save_to_db(FACTOR_CODE, SYMBOL, pub_date, obs_date, val, source_confidence=1.0, source="akshare_comex_inventory")        print(f"[OK] {FACTOR_CODE}={val:.3f} 写入成功")    else:        v = get_latest_value(FACTOR_CODE, SYMBOL)        if v is not None:            save_to_db(FACTOR_CODE, SYMBOL, pub_date, obs_date, v, source_confidence=0.5, source="db_回补")            print(f"[OK] {FACTOR_CODE}={v} L4回补成功")if __name__ == "__main__":    main()